value.value:
@if(
    or(
        or(
            startsWith(variables('FileType'), 'campaign'),
            startsWith(variables('FileType'), 'lead')
        ),
        or(
            startsWith(variables('FileType'), 'account'),
            startsWith(variables('FileType'), 'opportunity')
        )
    ),
    'CLAO_Files',
    if(
        equals(variables('FileType'), 'kohlerwimijobs'),
        'JobsFile',
        'unknownFile'
    )
)
